-- Caso: Promedio (clásico) | Nivel: Básico | Categoría: Clásicos | ID: C0642
-- Requisito (crear una sola vez):
-- CREATE TYPE dbo.IntList AS TABLE (pos INT NOT NULL, val BIGINT NOT NULL);
CREATE OR ALTER PROCEDURE dbo.sp_solve_c0642
  @arr dbo.IntList READONLY,
  @out FLOAT OUTPUT
AS
BEGIN

  DECLARE @n BIGINT = (SELECT COUNT(1) FROM @arr);
  IF (@n = 0) BEGIN SET @out = NULL; RETURN; END
  SELECT @out = (1.0 * SUM(val)) / @n FROM @arr;
END;
GO

