snippets.C0644:
-- Caso: Búsqueda binaria (clásico) | Nivel: Intermedio | Categoría: Clásicos | ID: C0644
-- Requisito (crear una sola vez):
-- CREATE TYPE dbo.IntList AS TABLE (pos INT NOT NULL, val BIGINT NOT NULL);
CREATE OR ALTER PROCEDURE dbo.sp_solve_c0644
  @arr dbo.IntList READONLY,
  @target BIGINT,
  @out INT OUTPUT
AS
BEGIN

  DECLARE @lo INT = 0;
  DECLARE @hi INT = (SELECT MAX(pos) FROM @arr);
  DECLARE @mid INT;
  DECLARE @v BIGINT;

  SET @out = -1;

  WHILE (@lo <= @hi)
  BEGIN
    SET @mid = (@lo + @hi) / 2;
    SELECT @v = val FROM @arr WHERE pos = @mid;

    IF (@v = @target)
    BEGIN
      SET @out = @mid;
      BREAK;
    END

    IF (@v < @target)
      SET @lo = @mid + 1;
    ELSE
      SET @hi = @mid - 1;
  END
END;
GO

snippets.C0645:
-- Caso: Validar brackets (clásico) | Nivel: Intermedio | Categoría: Clásicos | ID: C0645
-- Requisito (crear una sola vez):
-- CREATE TYPE dbo.IntList AS TABLE (pos INT NOT NULL, val BIGINT NOT NULL);
CREATE OR ALTER PROCEDURE dbo.sp_solve_c0645
  @s NVARCHAR(MAX),
  @out BIT OUTPUT
AS
BEGIN

  DECLARE @stack NVARCHAR(MAX) = N'';
  DECLARE @i INT = 1;
  DECLARE @n INT = LEN(@s);
  DECLARE @ch NCHAR(1);
  DECLARE @top NCHAR(1);

  SET @out = 1;

  WHILE (@i <= @n)
  BEGIN
    SET @ch = SUBSTRING(@s, @i, 1);

    IF (@ch IN (N'(', N'[', N'{'))
      SET @stack = @stack + @ch;
    ELSE IF (@ch IN (N')', N']', N'}'))
    BEGIN
      IF (LEN(@stack) = 0) BEGIN SET @out = 0; BREAK; END
      SET @top = SUBSTRING(@stack, LEN(@stack), 1);
      SET @stack = SUBSTRING(@stack, 1, LEN(@stack) - 1);

      IF ((@top = N'(' AND @ch <> N')') OR (@top = N'[' AND @ch <> N']') OR (@top = N'{' AND @ch <> N'}'))
      BEGIN
        SET @out = 0;
        BREAK;
      END
    END

    SET @i = @i + 1;
  END

  IF (@out = 1 AND LEN(@stack) <> 0) SET @out = 0;
END;
GO

