-- Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación | ID: C0646
CREATE OR ALTER FUNCTION dbo.validate_rut(@rut NVARCHAR(32))
RETURNS BIT
AS
BEGIN
  DECLARE @clean NVARCHAR(32) = UPPER(REPLACE(REPLACE(REPLACE(@rut, N'.', N''), N'-', N''), N' ', N''));
  IF (LEN(@clean) < 2) RETURN 0;

  DECLARE @body NVARCHAR(32) = LEFT(@clean, LEN(@clean)-1);
  DECLARE @dv   NCHAR(1)     = RIGHT(@clean, 1);

  IF (@body LIKE '%[^0-9]%') RETURN 0;

  DECLARE @sum INT = 0, @mul INT = 2, @i INT = LEN(@body), @d INT;
  WHILE (@i > 0)
  BEGIN
    SET @d = CONVERT(INT, SUBSTRING(@body, @i, 1));
    SET @sum = @sum + (@d * @mul);
    SET @mul = CASE WHEN @mul = 7 THEN 2 ELSE @mul + 1 END;
    SET @i = @i - 1;
  END

  DECLARE @mod INT = 11 - (@sum % 11);
  DECLARE @dvCalc NCHAR(1) =
    CASE WHEN @mod = 11 THEN N'0'
         WHEN @mod = 10 THEN N'K'
         ELSE CONVERT(NCHAR(1), @mod) END;

  RETURN CASE WHEN @dv = @dvCalc THEN 1 ELSE 0 END;
END;
GO

-- Demo
SELECT dbo.validate_rut(N'12.345.678-5') AS is_valid;
GO

